#include <stdio.h>
#include <math.h>
int main() {
    int n;
    scanf("%d", &n);
    int x[n], y[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &x[i], &y[i]);
    }
    int ans = 0;
    for (int i = 0; i < n; i++) {
        int cnt = 0;
        for (int j = 0; j < n; j++) {
            if (i != j) {
                double dist = sqrt(pow(x[i] - x[j], 2) + pow(y[i] - y[j], 2));
                if (dist <= 1) {
                    cnt++;
                }
            }
        }
        if (cnt == 0) {
            ans++;
        }
    }
    printf("%d\n", ans);
    return 0;
}

