const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let x = [];
let y = [];
let ans = 0;
let inputCount = 0;
rl.on('line', (input) => {
    if (inputCount == 0) {
        n = parseInt(input);
    } else {
        let coords = input.split(' ');
        x.push(parseInt(coords[0]));
        y.push(parseInt(coords[1]));
        if (inputCount == n) {
            for (let i = 0; i < n; i++) {
                let cnt = 0;
                for (let j = 0; j < n; j++) {
                    if (i != j) {
                        let dist = Math.sqrt(Math.pow(x[i] - x[j], 2) + Math.pow(y[i] - y[j], 2));
                        if (dist <= 1) {
                            cnt++;
                        }
                    }
                }
                if (cnt == 0) {
                    ans++;
                }
            }
            console.log(ans);
            rl.close();
        }
    }
    inputCount++;
});
